+/**
+ * Applies a rule while preserving recognized linter markers and text disabled
+ * for that rule by those markers.
+ */
+export function applyWithScopedRuleIgnores(text: string, ruleAlias: string, knownRuleAliases: string[], apply: (text: string) => string): string {
+  const lines = text.split('\
');
+  const knownAliases = new Set(knownRuleAliases.map((alias) => alias.toLowerCase()));
+  const protectedLines = new Set<number>();
+  const scopes: DisableScope[] = [];
+  let inFrontmatter = lines[0]?.trim() === '---';
+  let fence: string = null;
+  let inMathBlock = false;
+
+  for (let lineNumber = 0; lineNumber < lines.length; lineNumber++) {
+    const line = lines[lineNumber];
+    const trimmed = line.trim();
+    const ignoredContext = inFrontmatter || fence !== null || inMathBlock || indentedCodeRegex.test(line);
+    const marker = ignoredContext ? null : parseMarker(line, lineNumber);
+
+    if (marker !== null) {
+      protectedLines.add(lineNumber);
+      applyMarker(marker, scopes, knownAliases, lines.length, protectedLines);
+    } else if (isDisabled(ruleAlias, scopes)) {
+      protectedLines.add(lineNumber);
+    }
+
+    if (inFrontmatter && lineNumber > 0 && (trimmed === '---' || trimmed === '...')) {
+      inFrontmatter = false;
+    } else if (!inFrontmatter) {
+      const fenceMatch = line.match(fenceRegex);
+      if (fence === null && fenceMatch !== null) {
+        fence = fenceMatch[2][0];
+      } else if (fence !== null && fenceMatch !== null && fenceMatch[2][0] === fence) {
+        fence = null;
+      }
+
+      if (/^\\s*\\$\\$\\s*$/.test(line)) {
+        inMathBlock = !inMathBlock;
+      }
+    }
+  }
+
+  const replacements: string[] = [];
+  for (const lineNumber of protectedLines) {
+    const placeholder = `SCOPED_RULE_IGNORE_${replacements.length}_PLACEHOLDER`;
+    replacements.push(lines[lineNumber]);
+    lines[lineNumber] = placeholder;
+  }
+
+  let result = apply(lines.join('\
'));
+  replacements.forEach((line, index) => {
+    result = result.replace(`SCOPED_RULE_IGNORE_${index}_PLACEHOLDER`, line);
+  });
+  return result;
+}
+
+function parseMarker(line: string, lineNumber: number): Marker | null {
+  const match = line.match(markerRegex);
+  if (match === null) {
+    return null;
+  }
+
+  return {command: (match[1] ?? match[3]).toLowerCase(), ruleList: match[2] ?? match[4], line: lineNumber};
+}
+
+function normalizeRules(ruleList: string, knownAliases: Set<string>): Set<string> {
+  return new Set(ruleList.split(',').map((rule) => rule.trim().toLowerCase()).filter((rule) => rule !== '' && knownAliases.has(rule)));
+}
+
+function applyMarker(marker: Marker, scopes: DisableScope[], knownAliases: Set<string>, lineCount: number, protectedLines: Set<number>): void {
+  const isNextLine = marker.command === 'linter-disable-next-line';
+  const isNextNLines = marker.command.startsWith('linter-disable-next-n-lines');
+  const hasRuleList = marker.ruleList.trim() !== '';
+  const rules = normalizeRules(marker.ruleList, knownAliases);
+
+  if (isNextLine || isNextNLines) {
+    if (hasRuleList && rules.size === 0) return;
+    const countText = isNextNLines ? marker.command.match(/:\\s*(\\S+)$/)[1] : '1';
+    if (!/^\\d+$/.test(countText) || Number(countText) < 1) return;
+    const lastLine = Math.min(lineCount - 1, marker.line + Number(countText));
+    for (let line = marker.line + 1; line <= lastLine; line++) {
+      protectedLines.add(line);
+    }
+    return;
+  }
+
+  if (marker.command === 'linter-disable') {
+    if (hasRuleList && rules.size === 0) return;
+    scopes.push({all: !hasRuleList, rules, enabledRules: new Set()});
+    return;
+  }
+
+  if (marker.command === 'linter-enable') {
+    if (!hasRuleList) {
+      scopes.pop();
+      return;
+    }
+    for (const rule of rules) {
+      for (let index = scopes.length - 1; index >= 0; index--) {
+        const scope = scopes[index];
+        if (!scopeDisables(scope, rule)) continue;
+        if (scope.all) scope.enabledRules.add(rule);
+        else scope.rules.delete(rule);
+        if (!scope.all && scope.rules.size === 0) scopes.splice(index, 1);
+        break;
+      }
+    }
+  }
+}
+
+function scopeDisables(scope: DisableScope, ruleAlias: string): boolean {
+  return scope.all ? !scope.enabledRules.has(ruleAlias) : scope.rules.has(ruleAlias);
+}
+
+function isDisabled(ruleAlias: string, scopes: DisableScope[]): boolean {
+  return ruleAlias !== '' && scopes.some((scope) => scopeDisables(scope, ruleAlias.toLowerCase()));
+}
